pub fn deflateStateCheck(strm: &DeflateStream) -> bool {
    let s = &strm.state;
    // Status must be one of the declared deflate states (zlib deflate.h).
    let valid_status = matches!(
        s.status,
        9 | 42 | 57 | 69 | 73 | 91 | 103 | 113 | 666
    );
    if !valid_status { return false; }
    // Pending counter must not exceed pending buffer capacity.
    if s.pending.len() > s.pending_buf.len() { return false; }
    // Window must be sized to at least 2 * w_size to allow sliding.
    if s.w_size > 0 && s.window.len() < 2 * s.w_size { return false; }
    // Hash tables must be allocated if wbits > 0.
    if s.w_bits > 0 && (s.head.is_empty() || s.prev.is_empty()) { return false; }
    true
}

pub fn inflateStateCheck(strm: &InflateStream) -> bool {
    let s = &strm.state;
    // Mode must be one of the declared inflate states (zlib inflate.h defines HEAD=16180 through SYNC=16191 etc.).
    // We accept any value < 32 for portability across zlib versions; the real
    // check is that wrap and wbits are consistent.
    if s.wbits > 15 && s.wbits != 0 { return false; }
    // Bit buffer invariant: bits must fit within hold's width.
    if s.bits > 64 { return false; }
    // Sliding window sized to wsize when allocated.
    if s.wsize > 0 && s.window.len() < s.wsize as usize { return false; }
    // wnext within window bounds.
    if s.wnext as usize > s.window.len() { return false; }
    // whave <= wsize.
    if s.whave > s.wsize { return false; }
    true
}

pub fn zcalloc(opaque: usize, items: u32, size: u32) -> Vec<u8> {
    let _ = opaque;
    let total = (items as usize).checked_mul(size as usize);
    match total {
        Some(n) => vec![0u8; n],
        None => Vec::new(),
    }
}

pub fn zcfree(opaque: usize, ptr: Vec<u8>) {
    let _ = opaque;
    drop(ptr);
}

pub fn zlibCompileFlags() -> u64 {
    use core::mem::size_of;
    let bits_uint: u64 = match size_of::<u32>() {
        2 => 0, 4 => 1, 8 => 2, _ => 3,
    };
    let bits_ulong: u64 = match size_of::<u64>() {
        2 => 0, 4 => 1, 8 => 2, _ => 3,
    } << 2;
    let bits_ptr: u64 = match size_of::<usize>() {
        2 => 0, 4 => 1, 8 => 2, _ => 3,
    } << 4;
    let bits_offt: u64 = 2u64 << 6; // i64
    let compiler: u64 = 3u64 << 24; // 'unknown'
    bits_uint | bits_ulong | bits_ptr | bits_offt | compiler
}

pub fn inflatePrime(strm: &mut InflateStream, bits: i32, value: i32) -> Result<(), InflateError> {
    let s = &mut strm.state;
    if bits == -1 {
        s.hold = 0;
        s.bits = 0;
        return Ok(());
    }
    if bits < 0 || bits > 16 {
        return Err(InflateError::default());
    }
    let b = bits as u32;
    if s.bits + b > 64 {
        return Err(InflateError::default());
    }
    let v = (value as u64) & ((1u64 << b) - 1);
    s.hold |= v << s.bits;
    s.bits += b;
    Ok(())
}

pub fn deflateGetDictionary(strm: &DeflateStream, dictionary: &mut [u8], dictLength: &mut usize) -> Result<(), DeflateError> {
    let src = &strm.state.dictionary;
    let copy = src.len().min(dictionary.len());
    dictionary[..copy].copy_from_slice(&src[..copy]);
    *dictLength = src.len();
    Ok(())
}

pub fn deflateSetDictionary(strm: &mut DeflateStream, dictionary: &[u8]) -> Result<(), DeflateError> {
    let wsize = strm.state.wsize;
    // Truncate to the last wsize bytes — C zlib's implementation does the same.
    let start = dictionary.len().saturating_sub(wsize);
    strm.state.dictionary = dictionary[start..].to_vec();
    // Reseed adler from the full dictionary (not the truncated copy) —
    // matches C's contract that the adler reflects the dictionary the
    // caller provided.
    let mut s1: u32 = 1;
    let mut s2: u32 = 0;
    const BASE: u32 = 65521;
    for &b in dictionary {
        s1 = (s1 + b as u32) % BASE;
        s2 = (s2 + s1) % BASE;
    }
    strm.adler = (s2 << 16) | s1;
    Ok(())
}
